mapper.update:
/* OutboundBoxExportMapper.xml - updateOutboundBoxExportSendInterface - 부자재(출고박스)반출 인터페이스 송신 여부 UPDATE */
UPDATE TWORK_INFO_OB_HD
   SET OBBOXEXPTSNDYN = 'Y'
	 , UPDATEDATE = #{sysdate}
	 , UPDATEURKEY = 'BATCH'
WHERE CTKEY = #{ctkey}
AND OWKEY = #{owkey}
AND OBDDLNSNDRSLTCD = '20' /* 출고마감인터페이스 송신 정상 */
AND OBBOXEXPTSNDYN = 'N' /* 출고박스반출 인터페이스 미송신 */
AND OBCNFRMDATE  >=  TO_CHAR(TO_DATE(#{day},'YYYYMMDD') - 1, 'YYYYMMDD') || '000000'
AND OBCNFRMDATE  <  TO_CHAR(TO_DATE(#{day},'YYYYMMDD'),     'YYYYMMDD') || '000000'
